func complianceDecisionStyle(decision string) string {
	switch decision {
	case "confirmed":
		return "background:var(--green-bg,#e6f4ea);color:var(--green-fg,#1a7f37)"
	case "reverted":
		return "background:var(--red-bg,#fce8e6);color:var(--red-fg,#c00)"
	default:
		return "background:var(--orange-bg,#fff3cd);color:var(--orange-fg,#856404)"
	}
}

func complianceDecisionLabel(decision string) string {
	switch decision {
	case "confirmed":
		return "Confirmed"
	case "reverted":
		return "Reverted"
	default:
		return "Unreviewed"
	}
}

func complianceCatClass(cat string) string {
	switch cat {
	case "external_dependency":
		return "dep"
	case "external_api", "network_access":
		return "net"
	case "database_operation":
		return "db"
	case "filesystem_operation":
		return "fs"
	case "privilege_pattern":
		return "priv"
	default:
		return "net"
	}
}

