func complianceShortID(id string) string {
	parts := strings.Split(id, ":")
	if len(parts) <= 3 {
		return id
	}
	return strings.Join(parts[len(parts)-2:], ":")
}

func complianceControlSummary(refs []compliance.ControlRef) string {
	if len(refs) == 0 {
		return "—"
	}
	ids := make([]string, 0, len(refs))
	for _, r := range refs {
		ids = append(ids, r.ControlID)
	}
	if len(ids) > 3 {
		return strings.Join(ids[:3], ", ") + fmt.Sprintf(" +%d", len(ids)-3)
	}
	return strings.Join(ids, ", ")
}

