func complianceUnconfirmedStyle(n int) string {
	if n > 0 {
		return "color:#856404"
	}
	return "color:#1a7f37"
}

func complianceFwLabel(fw string, versions []compliance.FrameworkVersion) string {
	if fw == "all" || fw == "" {
		return "All Frameworks"
	}
	for _, v := range versions {
		if v.Key == fw {
			return v.Name
		}
	}
	return strings.ToUpper(fw)
}

func pluralCapability(n int) string {
	if n == 1 {
		return "capability"
	}
	return "capabilities"
}

